#!/usr/bin/env node

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const scriptDir = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(scriptDir, '../../..');
const fixturePath = path.join(
  repoRoot,
  'open-source/gnosis/polyglot/tests/fixtures/bwtr-v1.json'
);
const leanPath = path.join(
  repoRoot,
  'open-source/gnosis-math/Gnosis/PleromaAeonMonsterBridge.lean'
);

const beginMarker = '/- BEGIN GENERATED BWTR V1 FIXTURE.';
const endMarker = '/- END GENERATED BWTR V1 FIXTURE -/';

function formatNatList(values, indent = 6, maxPerLine = 18) {
  const lines = [];
  for (let i = 0; i < values.length; i += maxPerLine) {
    lines.push(
      `${' '.repeat(indent)}${values.slice(i, i + maxPerLine).join(', ')}`
    );
  }
  if (lines.length === 1) {
    return `[${values.join(', ')}]`;
  }
  return `[\n${lines.join(',\n')}]`;
}

function requiredNumber(value, label) {
  if (!Number.isInteger(value) || value < 0) {
    throw new Error(`${label} must be a nonnegative integer`);
  }
  return value;
}

const fixtureFile = JSON.parse(fs.readFileSync(fixturePath, 'utf8'));
const fixture = fixtureFile.fixtures?.find(
  (entry) => entry.name === 'fork-future-carrier-user-789'
);

if (!fixture) {
  throw new Error('missing BWTR fixture fork-future-carrier-user-789');
}

const bytes = fixture.bytes?.map((value, index) =>
  requiredNumber(value, `bytes[${index}]`)
);
const budgetBytes = fixture.work?.budgetBytes?.map((value, index) =>
  requiredNumber(value, `work.budgetBytes[${index}]`)
);

if (!bytes || !budgetBytes) {
  throw new Error('fixture must carry bytes and work.budgetBytes arrays');
}

const generated = `${beginMarker} Run:
   node open-source/gnosis/scripts/generate-bwtr-lean-fixture.mjs
   Source: open-source/gnosis/polyglot/tests/fixtures/bwtr-v1.json -/
/-- Runtime fixture generated from \`polyglot/tests/fixtures/bwtr-v1.json\`. -/
def bwtrForkFutureCarrierFixture : BwtrWirePayload where
  phaseTag := ${requiredNumber(fixture.work.phaseTag, 'work.phaseTag')}
  clockPhase := ${requiredNumber(fixture.work.clockPhase, 'work.clockPhase')}
  carrierKey := ${requiredNumber(fixture.work.carrierKey, 'work.carrierKey')}
  seenCanonicalC2Key := ${requiredNumber(
    fixture.work.seenCanonicalC2Key,
    'work.seenCanonicalC2Key'
  )}
  reserved := ${requiredNumber(fixture.work.reserved, 'work.reserved')}
  budgetBytes := ${formatNatList(budgetBytes, 18)}
  userBytes := ${formatNatList(fixture.userId.split('').map((char) => char.charCodeAt(0)), 15)}

theorem bwtr_fixture_roundtrip :
    decodeBwtrWirePayload (encodeBwtrWirePayload bwtrForkFutureCarrierFixture) =
      some bwtrForkFutureCarrierFixture := by
  exact bwtr_wire_payload_roundtrip bwtrForkFutureCarrierFixture rfl

theorem bwtr_fixture_encoded_bytes :
    encodeBwtrWirePayload bwtrForkFutureCarrierFixture =
${formatNatList(bytes, 6)} := by
  native_decide
${endMarker}`;

const leanSource = fs.readFileSync(leanPath, 'utf8');
const begin = leanSource.indexOf(beginMarker);
const end = leanSource.indexOf(endMarker, begin);

if (begin < 0 || end < 0) {
  throw new Error('generated BWTR fixture markers not found in Lean bridge');
}

const nextSource =
  leanSource.slice(0, begin) +
  generated +
  leanSource.slice(end + endMarker.length);

fs.writeFileSync(leanPath, nextSource);
console.log(
  `Generated BWTR Lean fixture from ${path.relative(repoRoot, fixturePath)}`
);
